// The ensures of det_proc_to_page is an implication
//     (A_r1 && A_r2) ==> det_proc_to_page_equal(r1, r2)
// where A_ri is the postcondition of `proc_to_page` applied to ri.
// The previous attempt asserted the conjuncts of the antecedent
// directly at the top of the body, which fails because the antecedent
// is NOT a fact in scope — it is the hypothesis side of the
// implication.  Instead, re-introduce it through an `if`, so Verus
// adds the path-condition `A_r1 && A_r2` to context and we can lift
// each observable conjunct into the pointwise relation between r1
// and r2 that `det_proc_to_page_equal` is built from.
if (r1.0 == proc_ptr) && (r1.1@.is_init()) && (r1.1@.addr() == r1.0)
    && (r2.0 == proc_ptr) && (r2.1@.is_init()) && (r2.1@.addr() == r2.0) {
    // r1.0 and r2.0 are both pinned to proc_ptr, so they are equal.
    assert(r1.0 == proc_ptr);
    assert(r2.0 == proc_ptr);
    assert(r1.0 == r2.0);

    // is_init is pinned to `true` on both sides.
    assert(r1.1@.is_init());
    assert(r2.1@.is_init());
    assert(r1.1@.is_init() == r2.1@.is_init());

    // addr() is pinned to ret.0 == proc_ptr on both sides, so the two
    // views have the same addr.
    assert(r1.1@.addr() == r1.0);
    assert(r2.1@.addr() == r2.0);
    assert(r1.1@.addr() == r2.1@.addr());
}
